parameters.jsonBody:
={
  "model": "llama-3.3-70b-versatile",
  "max_tokens": 600,
  "messages": [
    {
      "role": "system",
      "content": "You are a helpful government complaint assistant for District Administration Kurukshetra, Haryana. Your job is to:
1. Improve the citizen's complaint text — make it clear, formal, and actionable
2. Keep the same facts but improve grammar and structure
3. Respond in the SAME language the citizen used (Hindi/English/Punjabi)
4. Keep it under 150 words
5. Start with 'Respected Sir/Madam' or 'आदरणीय महोदय'
6. End with citizen's name and address

Also at the end on a new line write:
DEPARTMENT: [PENSION/AADHAAR/PPP/RATION/REVENUE/CRED/OTHERS]
PRIORITY: [High/Medium/Low]
SUMMARY: [one line summary]"
    },
    {
      "role": "user",
      "content": "Citizen Name: {{ $json.name }}
Address: {{ $json.address }}
Category: {{ $json.category }}
Preferred Language: {{ $json.language }}
Original Complaint:
{{ $json.ai_improved_text !== '' && $json.ai_improved_text !== undefined ? $json.ai_improved_text : $json.complaint_text }}"
    }
  ]
}

parameters.jsCode:
const aiText = $input.item.json.choices[0].message.content;
const form = $('Citizen Complaint Form').item.json;

// Extract metadata
const deptMatch = aiText.match(/DEPARTMENT:\s*(\w+)/i);
const priorityMatch = aiText.match(/PRIORITY:\s*(\w+)/i);
const summaryMatch = aiText.match(/SUMMARY:\s*(.+)/i);

const dept = deptMatch ? deptMatch[1].toUpperCase().trim() : 'OTHERS';
const priority = priorityMatch ? priorityMatch[1].trim() : 'Medium';
const summary = summaryMatch ? summaryMatch[1].trim() : form.complaint_text.slice(0, 100);

// Clean improved text (remove metadata lines)
const improvedText = aiText
  .replace(/DEPARTMENT:.*$/mi, '')
  .replace(/PRIORITY:.*$/mi, '')
  .replace(/SUMMARY:.*$/mi, '')
  .trim();

// Department routing
const routingMap = {
  'PENSION': { email: 'REPLACE_WITH_PENSION_OFFICER_EMAIL@example.gov.in', label: 'DSWO (Pension)', whatsapp: 'whatsapp:REPLACE_WITH_PENSION_OFFICER_WHATSAPP' },
  'AADHAAR': { email: 'REPLACE_WITH_AADHAAR_OFFICER_EMAIL@example.gov.in', label: 'ADC (Aadhaar)', whatsapp: 'whatsapp:REPLACE_WITH_AADHAAR_OFFICER_WHATSAPP' },
  'PPP':     { email: 'REPLACE_WITH_PPP_OFFICER_EMAIL@example.gov.in', label: 'ADC (PPP)', whatsapp: 'whatsapp:REPLACE_WITH_PPP_OFFICER_WHATSAPP' },
  'RATION':  { email: 'REPLACE_WITH_RATION_OFFICER_EMAIL@example.gov.in', label: 'DFSC (Ration)', whatsapp: 'whatsapp:REPLACE_WITH_RATION_OFFICER_WHATSAPP' },
  'REVENUE': { email: 'REPLACE_WITH_REVENUE_OFFICER_EMAIL@example.gov.in', label: 'DRO (Revenue)', whatsapp: 'whatsapp:REPLACE_WITH_REVENUE_OFFICER_WHATSAPP' },
  'CRED':    { email: 'REPLACE_WITH_CRED_OFFICER_EMAIL@example.gov.in', label: 'ADC (CRED)', whatsapp: 'whatsapp:REPLACE_WITH_CRED_OFFICER_WHATSAPP' },
  'OTHERS':  { email: 'REPLACE_WITH_DEFAULT_OFFICER_EMAIL@example.gov.in', label: 'DC Office', whatsapp: 'whatsapp:REPLACE_WITH_DEFAULT_OFFICER_WHATSAPP' }
};

const route = routingMap[dept] || routingMap['OTHERS'];
const refNumber = '#' + $('Citizen Complaint Form').item.json.name.slice(0,2).toUpperCase() + Date.now().toString().slice(-6);

// Format phone for Twilio
let phone = form.phone.replace(/\s/g, '');
if (!phone.startsWith('+')) phone = '+91' + phone;
const twilioPhone = 'whatsapp:' + phone;

return {
  json: {
    name: form.name,
    phone: form.phone,
    email: form.email,
    address: form.address,
    category: form.category,
    language: form.language,
    originalText: form.complaint_text,
    improvedText: improvedText,
    department: dept,
    priority: priority,
    summary: summary,
    officerEmail: route.email,
    officerLabel: route.label,
    officerWhatsApp: route.whatsapp,
    citizenWhatsApp: twilioPhone,
    refNumber: refNumber,
    timestamp: new Date().toLocaleString('en-IN', { timeZone: 'Asia/Kolkata' })
  }
};

